import { randomBytes, scryptSync } from 'node:crypto'

export function generateSalt(bytes = 16): string {
  return randomBytes(bytes).toString('hex')
}

export function hashPassword(pw: string, salt: string): string {
  return scryptSync(pw, salt, 64).toString('hex')
}

export function verifyPassword(pw: string, salt: string, hash: string): boolean {
  return hashPassword(pw, salt) === hash
}

